  ('social-worker-moex-05422', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '民事保護令是指保護家庭暴力被害人的人身安全與權益的法律命令，警告相對人不能再用肢體暴力、言 詞暴力對待被害人。家庭暴力防治法第9條規定民事保護令分成三種，其中不包含下列那一種保護令？', '["暫時保護令", "禁制保護令", "緊急保護令", "通常保護令"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
